import React from 'react';
import CheckpointCard from './CheckpointCard';
import { CheckpointListProps } from './checkpointListTypes';
import { useCheckpointListControls } from './useCheckpointListControls';

const CheckpointList: React.FC<CheckpointListProps> = ({
  run,
  template,
  isTerminal,
  isPaused,
  checkpointRequirements,
  evaluateRequirementDetails,
  reusablePoolAssets,
  onContinue,
  onRegenerate,
  onInjectPrompt,
  onAddAttachment,
}) => {
  const controls = useCheckpointListControls({
    reusablePoolAssets,
    onContinue,
    onRegenerate,
    onInjectPrompt,
    onAddAttachment,
  });

  return (
    <>
      {template.checkpoints.map((checkpoint, index) => (
        <CheckpointCard
          key={checkpoint.id}
          run={run}
          template={template}
          index={index}
          isTerminal={isTerminal}
          isPaused={isPaused}
          checkpointRequirements={checkpointRequirements}
          evaluateRequirementDetails={evaluateRequirementDetails}
          reusablePoolAssets={reusablePoolAssets}
          selectedCheckpoint={controls.selectedCheckpoint}
          setSelectedCheckpoint={controls.setSelectedCheckpoint}
          selectedAssetByCheckpoint={controls.selectedAssetByCheckpoint}
          setSelectedAssetByCheckpoint={controls.setSelectedAssetByCheckpoint}
          attachLoadingByCheckpoint={controls.attachLoadingByCheckpoint}
          attachErrorByCheckpoint={controls.attachErrorByCheckpoint}
          injectTextByCheckpoint={controls.injectTextByCheckpoint}
          setInjectTextByCheckpoint={controls.setInjectTextByCheckpoint}
          injectModeByCheckpoint={controls.injectModeByCheckpoint}
          setInjectModeByCheckpoint={controls.setInjectModeByCheckpoint}
          injectLoadingByCheckpoint={controls.injectLoadingByCheckpoint}
          injectErrorByCheckpoint={controls.injectErrorByCheckpoint}
          progressionLoadingByCheckpoint={controls.progressionLoadingByCheckpoint}
          progressionErrorByCheckpoint={controls.progressionErrorByCheckpoint}
          requiredReferencePromptByCheckpoint={controls.requiredReferencePromptByCheckpoint}
          setInjectErrorByCheckpoint={controls.setInjectErrorByCheckpoint}
          onAttachFromPool={controls.handleAttachFromPool}
          onInjectPrompt={controls.handleInjectPrompt}
          onContinue={controls.handleContinue}
          onRegenerate={controls.handleRegenerate}
        />
      ))}
    </>
  );
};

export default CheckpointList;
